+/*  \file   CudnnLibrary.h
+    \date   April 22, 2015
+    \author Gregory Diamos <solusstultus@gmail.com>
+    \brief  The header file for the CudnnLibrary class.
+*/
+
+#pragma once
+
+// Standard Library Includes
+#include <cstddef>
+#include <string>
+
+// Forward Declarations
+typedef struct cudnnTensorStruct*      cudnnTensorDescriptor_t;
+typedef struct cudnnConvolutionStruct* cudnnConvolutionDescriptor_t;
+typedef struct cudnnPoolingStruct*     cudnnPoolingDescriptor_t;
+typedef struct cudnnFilterStruct*      cudnnFilterDescriptor_t;
+typedef struct cudnnDropoutStruct*     cudnnDropoutDescriptor_t;
+typedef struct cudnnRNNStruct*         cudnnRNNDescriptor_t;
+
+namespace prnn
+{
+
+namespace matrix
+{
+
+/*! \brief A singleton interface to CUDNN if it is dynamically loaded. */
+class CudnnLibrary
+{
+public:
+    typedef enum
+    {
+        CUDNN_STATUS_SUCCESS          = 0,
+        CUDNN_STATUS_NOT_INITIALIZED  = 1,
+        CUDNN_STATUS_ALLOC_FAILED     = 2,
+        CUDNN_STATUS_BAD_PARAM        = 3,
+        CUDNN_STATUS_INTERNAL_ERROR   = 4,
+        CUDNN_STATUS_INVALID_VALUE    = 5,
+        CUDNN_STATUS_ARCH_MISMATCH    = 6,
+        CUDNN_STATUS_MAPPING_ERROR    = 7,
+        CUDNN_STATUS_EXECUTION_FAILED = 8,
+        CUDNN_STATUS_NOT_SUPPORTED    = 9,
+        CUDNN_STATUS_LICENSE_ERROR    = 10
+    } cudnnStatus_t;
+
+    /* CUDNN data type */
+    typedef enum
+    {
+        CUDNN_DATA_FLOAT  = 0,
+        CUDNN_DATA_DOUBLE = 1,
+        CUDNN_DATA_HALF   = 2
+    } cudnnDataType_t;
+
+    typedef enum
+    {
+        CUDNN_TENSOR_NCHW = 0,   /* row major (wStride = 1, hStride = w) */
+        CUDNN_TENSOR_NHWC = 1    /* feature maps interleaved ( cStride = 1 )*/
+    } cudnnTensorFormat_t;
+
+    /* convolution mode */
+    typedef enum
+    {
+        CUDNN_CONVOLUTION       = 0,
+        CUDNN_CROSS_CORRELATION = 1
+    } cudnnConvolutionMode_t;
+
+    typedef enum
+    {
+        CUDNN_CONVOLUTION_FWD_NO_WORKSPACE        = 0,
+        CUDNN_CONVOLUTION_FWD_PREFER_FASTEST      = 1,
+        CUDNN_CONVOLUTION_FWD_SPECIFY_WORKSPACE_LIMIT = 2,
+    } cudnnConvolutionFwdPreference_t;
+
+    typedef enum
+    {
+        CUDNN_CONVOLUTION_FWD_ALGO_IMPLICIT_GEMM         = 0,
+        CUDNN_CONVOLUTION_FWD_ALGO_IMPLICIT_PRECOMP_GEMM = 1,
+        CUDNN_CONVOLUTION_FWD_ALGO_GEMM                  = 2,
+        CUDNN_CONVOLUTION_FWD_ALGO_DIRECT                = 3
+    } cudnnConvolutionFwdAlgo_t;
+
+    typedef enum
+    {
+        CUDNN_CONVOLUTION_BWD_DATA_NO_WORKSPACE             = 0,
+        CUDNN_CONVOLUTION_BWD_DATA_PREFER_FASTEST           = 1,
+        CUDNN_CONVOLUTION_BWD_DATA_SPECIFY_WORKSPACE_LIMIT  = 2,
+    } cudnnConvolutionBwdDataPreference_t;
+
+    typedef enum
+    {
+        CUDNN_CONVOLUTION_BWD_DATA_ALGO_0          = 0, // non-deterministic
+        CUDNN_CONVOLUTION_BWD_DATA_ALGO_1          = 1,
+        CUDNN_CONVOLUTION_BWD_DATA_ALGO_FFT        = 2,
+        CUDNN_CONVOLUTION_BWD_DATA_ALGO_FFT_TILING = 3
+    } cudnnConvolutionBwdDataAlgo_t;
+
+    typedef enum
+    {
+        CUDNN_CONVOLUTION_BWD_FILTER_NO_WORKSPACE            = 0,
+        CUDNN_CONVOLUTION_BWD_FILTER_PREFER_FASTEST          = 1,
+        CUDNN_CONVOLUTION_BWD_FILTER_SPECIFY_WORKSPACE_LIMIT = 2,
+    } cudnnConvolutionBwdFilterPreference_t;
+
+    typedef enum
+    {
+        CUDNN_CONVOLUTION_BWD_FILTER_ALGO_0         = 0,  // non-deterministic
+        CUDNN_CONVOLUTION_BWD_FILTER_ALGO_1         = 1,
+        CUDNN_CONVOLUTION_BWD_FILTER_ALGO_FFT       = 2,
+        CUDNN_CONVOLUTION_BWD_FILTER_ALGO_3         = 3   // non-deterministic, algo0 with workspace
+    } cudnnConvolutionBwdFilterAlgo_t;
+
+    typedef enum
+    {
+        CUDNN_POOLING_MAX     = 0,
+        CUDNN_POOLING_AVERAGE_COUNT_INCLUDE_PADDING = 1,
+        CUDNN_POOLING_AVERAGE_COUNT_EXCLUDE_PADDING = 2
+    } cudnnPoolingMode_t;
+
+
+    typedef enum
+    {
+        CUDNN_RNN_RELU = 0, // Stock RNN with ReLu activation
+        CUDNN_RNN_TANH = 1, // Stock RNN with tanh activation
+        CUDNN_LSTM     = 2, // LSTM with no peephole connections
+        CUDNN_GRU      = 3  // Using h' = tanh(r * Uh(t-1) + Wx) and h = (1 - z) * h' + z * h(t-1);
+    } cudnnRNNMode_t;
+
+    typedef enum
+    {
+       CUDNN_UNIDIRECTIONAL = 0,
+       CUDNN_BIDIRECTIONAL = 1   // Using output concatination at each step. Do we also want to support output sum?
