+                    blockIdx.x, blockIdx.y, threadIdx.x, threadIdx.y,
+                    offset + i, block_offset, thread_offset, value_offset + i,
+                    output_base + offset + i,
+                    (float)reinterpret_cast<GlobalAccessType&>(data).data[i]);
+            }
